library ieee;
use ieee.std_logic_1164.all;

entity parity_check_16bit is
  port (
    data_in : in std_logic_vector(15 downto 0);
    enable : in std_logic;
    parity_out : out std_logic
  );
end parity_check_16bit;

architecture rtl of parity_check_16bit is
begin
  process(data_in)
  begin
    if enable = '1' then
      parity_out <= xor data_in;
    else
      parity_out <= '0';
    end if;
  end process;
end rtl;

